// 6.3 — default skin pro Ikaros UI (synthwave tmavé). Změna proti starému
// Matrixu (`core-ivory`) — Obsidian + cyan glyf ladí s brandem.
export const DEFAULT_SKIN_ID = 'core-obsidian';

export const CATEGORY_LABELS: Record<string, string> = {
  core: 'Základní',
  elemental: 'Elementální',
  draconic: 'Dračí',
  undead: 'Nemrtví',
  nature: 'Přírodní',
};

export const CATEGORY_ORDER = [
  'core',
  'elemental',
  'draconic',
  'undead',
  'nature',
] as const;

export function getDiceSkin(skinId: string | null | undefined): FateDiceSkin {
  if (!skinId) {
    return (
      FATE_DICE_SKINS.find((s) => s.id === DEFAULT_SKIN_ID) ||
      FATE_DICE_SKINS[0]
    );
  }
  return (
    FATE_DICE_SKINS.find((s) => s.id === skinId) ||
    FATE_DICE_SKINS.find((s) => s.id === DEFAULT_SKIN_ID) ||
    FATE_DICE_SKINS[0]
  );
}

/** @deprecated alias pro `getDiceSkin` z důvodů kompatibility. */
export const getFateSkin = getDiceSkin;

export function getSkinsByCategory(): Record<string, FateDiceSkin[]> {
  const acc: Record<string, FateDiceSkin[]> = {};
  FATE_DICE_SKINS.forEach((skin) => {
    if (!acc[skin.category]) acc[skin.category] = [];
    acc[skin.category].push(skin);
  });
  return acc;
}

